# Caso: Two Sum | Nivel: Intermedio | Categoría: Map/Hash

def solve(arr, target)
  seen = {}
  arr.each_with_index do |x, i|
    need = target - x
    return [seen[need], i] if seen.key?(need)
    seen[x] = i
  end
  nil
end

