# C0652 · Validar JSON contra Schema (Intermedio, Validación)
# Ruby · json_schemer
# gem install json_schemer
require "json_schemer"

def solve
  schema = JSONSchemer.schema({
    "type"=>"object",
    "required"=>["name","qty"],
    "properties"=>{"name"=>{"type"=>"string"}, "qty"=>{"type"=>"integer","minimum"=>1}}
  })
  data = {"name"=>"Item","qty"=>1}
  errors = schema.validate(data).to_a
  { ok: errors.empty?, errors: }
end

