# C0660 · CLI real (args + env + help) (Intermedio, CLI)
require "optparse"

def solve(argv=ARGV)
  opts = { verbose: false }
  OptionParser.new do |o|
    o.on("--input PATH"){|v| opts[:input]=v}
    o.on("--output PATH"){|v| opts[:output]=v}
    o.on("--verbose"){ opts[:verbose]=true }
  end.parse!(argv)
  opts[:env] = ENV["APP_ENV"] || "dev"
  opts
end

