# C0669 · LRU cache (Intermedio, Algoritmos)
# Ruby: Hash mantiene orden de inserción; para LRU "re-insertar" clave.
class LRU
  def initialize(cap)
    @cap = cap
    @h = {}
  end

  def get(k)
    return nil unless @h.key?(k)
    v = @h.delete(k)
    @h[k] = v
    v
  end

  def put(k, v)
    @h.delete(k) if @h.key?(k)
    @h[k] = v
    if @h.length > @cap
      oldest = @h.keys.first
      @h.delete(oldest)
    end
  end
end
